import { describe, it, expect, beforeEach } from 'vitest';
import { AuthService } from '../index.js';

function resetAuth(): void {
  void AuthService.logout();
  const usersMap = (AuthService as unknown as { users: Map<string, unknown> }).users;
  usersMap.clear();
}

describe('AuthService', () => {
  beforeEach(() => {
    resetAuth();
  });

  it('register creates user, login succeeds with correct credentials', async () => {
    const registerResult = await AuthService.register('alice@test.com', 'secret123');
    expect(registerResult.success).toBe(true);
    expect(registerResult.user).not.toBeNull();
    expect(registerResult.user!.email).toBe('alice@test.com');

    await AuthService.logout();

    const loginResult = await AuthService.login('alice@test.com', 'secret123');
    expect(loginResult.success).toBe(true);
    expect(loginResult.user).not.toBeNull();
    expect(loginResult.user!.email).toBe('alice@test.com');
  });

  it('login fails with wrong password', async () => {
    await AuthService.register('bob@test.com', 'correct-password');
    await AuthService.logout();

    const result = await AuthService.login('bob@test.com', 'wrong-password');
    expect(result.success).toBe(false);
    expect(result.error).toBe('Invalid email or password');
    expect(result.user).toBeNull();
  });

  it('getSession returns null before login, user after login', async () => {
    const beforeLogin = await AuthService.getSession();
    expect(beforeLogin).toBeNull();

    await AuthService.register('charlie@test.com', 'password');
    const afterRegister = await AuthService.getSession();
    expect(afterRegister).not.toBeNull();
    expect(afterRegister!.email).toBe('charlie@test.com');
  });

  it('getLicenseStatus returns free for new free-tier users', async () => {
    await AuthService.register('dave@test.com', 'password', 'free');
    const license = await AuthService.getLicenseStatus();
    expect(license.tier).toBe('free');
    expect(license.isValid).toBe(true);
  });

  it("canAccess('pro-features') returns false for free tier", async () => {
    await AuthService.register('eve@test.com', 'password', 'free');
    expect(AuthService.canAccess('pro-features')).toBe(false);
  });

  it("canAccess('pro-features') returns true for pro tier", async () => {
    await AuthService.register('frank@test.com', 'password', 'pro');
    expect(AuthService.canAccess('pro-features')).toBe(true);
  });

  it('logout clears session', async () => {
    await AuthService.register('grace@test.com', 'password');
    expect(await AuthService.getSession()).not.toBeNull();

    await AuthService.logout();
    const session = await AuthService.getSession();
    expect(session).toBeNull();
  });
});
