    const cfg = this.getConfig();
    // Reset fuel based on scenario
    if (cfg.fuelBehavior === 'full' || cfg.fuelBehavior === 'decreasing') {
      this.fuelLevel = this.fuelCapacity;
    } else if (cfg.fuelBehavior === 'low') {
      this.fuelLevel = 15;
    } else if (cfg.fuelBehavior === 'increasing') {
