    const gear = this.generateGear(cfg, speed);
    const flags = this.generateFlags(cfg);

    return {
      sim: 'iracing',
      timestamp: Date.now() + this.tickCount * 16,
      isConnected: true,
      player: {
        speed,
        rpm,
        gear,
        isOnTrack: cfg.isOnTrack,
