        totalLaps: cfg.fuelBehavior === 'decreasing' ? 30 : 10,
        lastLaptime: cfg.baseLaptime + this.rng.nextInt(-2000, 3000),
        bestLaptime: cfg.baseLaptime - this.rng.nextInt(1000, 3000),
