function getStr(d: Record<string, unknown>, k: string, fb = ''): string {
  return str(fb).parse(d[k]);
}

function getBool(d: Record<string, unknown>, k: string, fb = false): boolean {
  return bool(fb).parse(d[k]);
}

function getObj(d: Record<string, unknown>, k: string): Record<string, unknown> {
  return obj().parse(d[k]);
}

// ──────────────────────────────────────────────
